class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        List<Integer> result = new ArrayList<>();
        backtrack(result, num, 0);
        return result;
    }

    private boolean backtrack(List<Integer> result, String num, int start) {
        if (start == num.length() && result.size() >= 3) {
            return true;
        }
        for (int i = start; i < num.length(); i++) {
            if (num.charAt(start) == '0' && i > start) {
                break;
            }
            String cur = num.substring(start, i + 1);
            long x = Long.parseLong(cur);
            if (x > Integer.MAX_VALUE) {
                break;
            }
            int size = result.size();
            if (size >= 2 && x > result.get(size - 1) + result.get(size - 2)) {
                break;
            }
            if (size <= 1 || x == result.get(size - 1) + result.get(size - 2)) {
                result.add((int) x);
                if (backtrack(result, num, i + 1)) {
                    return true;
                }
                result.remove(result.size() - 1);
            }
        }
        return false;
    }
}
